      which is capable of creating and running small Flutter apps.

      Without this we will unlikely be able to progress on the issue, and because of that
      we regretfully will have to close it.
-->

The behavior is identical even if you exchange `MyPopupContent` with a simple `TextField`. 

```dart
import 'package:flutter/material.dart';

void main() {
  runApp(const MyApp());
}

class MyPopupContent extends StatelessWidget {
  const MyPopupContent({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return Card(
        margin: const EdgeInsets.all(12.0),
        shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.all(
            Radius.circular(16),
          ),
        ),
        child: Padding(
            padding: const EdgeInsets.all(12.0),
            child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.center,
                mainAxisAlignment: MainAxisAlignment.end,
                children: [
                  const Icon(Icons.home),
                  const Text("hello"),
                  const TextField(autofocus: true),
                  ElevatedButton(
                      onPressed: () {}, child: const Text("ElevatedButton"))
                ])));
  }
}

class MyApp extends StatelessWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatelessWidget {
  const MyHomePage({Key? key, required this.title}) : super(key: key);
  final String title;

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text(title),
      ),
      body: Center(
        child: Column(
          children: [
            ElevatedButton(
              onPressed: () {
                showDialog(
                    context: context,
                    builder: (context) {
                      return const Dialog(child: MyPopupContent());
                    });
              },
              child:
                  const Text("Show dialog: content wrapped with Dialog widget"),
            ),
            ElevatedButton(
              onPressed: () {
                showDialog(
                    context: context,
                    builder: (context) {
                      return AnimatedPadding(
                          padding: EdgeInsets.only(
                              bottom: MediaQuery.of(context).viewInsets.bottom),
                          duration: const Duration(milliseconds: 100),
                          child: Center(
                              child: Wrap(children: const [MyPopupContent()])));
                    });
              },
              child: const Text(
                  "Show dialog: content wrapped with AnimatedPadding widget"),
            ),
            ElevatedButton(
              onPressed: () {
                showDialog(
                    context: context,
                    builder: (context) {
                      return const AlertDialog(
                        title: Text("AlertDialog"),
                        content: MyPopupContent(),
                      );
                    });
              },
              child: const Text(
                  "Show dialog: content wrapped with AlertDialog widget"),
            ),
          ],
        ),
      ),
    );
  }
}

