### Steps to reproduce

1. See code sample on how to reproduce it.
2. We want to have accessibility support so app is calling SemanticsBinding.instance.ensureSemantics();
3. Launch code sample as a web application.
4. Connect to application from mobile browser like Chrome on an Android or Safari on iOS.
5. Do not use physical keyboard, ensure you are using on-screen soft keyboard.


### Expected results

I expect to be able to switch between visible widgets using + and - minus buttons and use the on-screen soft keyboard to enter text into TextFields in the different widgets.

### Actual results

Try to enter text into TextField in the different widgets, step between them using + and -  buttons. See that some will not work with soft keyboard, the soft keyboard disappears immediately upon focusing the TextField. See video.

If the Visibility widget is removed in the sample code all TextFields works as expected.
If call to SemanticsBinding.instance.ensureSemantics() is removed TextFields also works as expected.

So the combination of using Visibility widget and ensureSemantics is causing this issue.

### Code sample

<details open><summary>Code sample</summary>

```dart
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';
import 'package:flutter/rendering.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  if (kIsWeb) {
    // This is to opt-in for accessibility on the web
    SemanticsBinding.instance.ensureSemantics();
  }

  runApp(const MyApp());
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Flutter Demo',
      theme: ThemeData(
        colorScheme: ColorScheme.fromSeed(seedColor: Colors.deepPurple),
        useMaterial3: true,
      ),
      home: const MyHomePage(title: 'Flutter Demo Home Page'),
    );
  }
}

class MyHomePage extends StatefulWidget {
  const MyHomePage({super.key, required this.title});

  final String title;

  @override
  State<MyHomePage> createState() => _MyHomePageState();
}

class _MyHomePageState extends State<MyHomePage> {
  int _index = 0;
  int widgets = 10;

  void _incrementindex() {
    setState(() {
      if (_index < widgets - 1) _index++;
    });
  }

  void _decrementIndex() {
    setState(() {
      if (_index > 0) _index--;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        backgroundColor: Theme.of(context).colorScheme.inversePrimary,
        title: Text(widget.title),
      ),
      body: SafeArea(
        child: Center(
          child: Padding(
            padding: const EdgeInsets.all(48.0),
            child: SingleChildScrollView(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  for (int i = 0; i < widgets; i++) ...[
                    InputWidget(title: i.toString(), expanded: i == _index),
                    SizedBox(height: 10),
                  ]
                ],
              ),
            ),
          ),
        ),
      ),
      floatingActionButton: Column(
        mainAxisAlignment: MainAxisAlignment.end,
        children: [
          FloatingActionButton(
            onPressed: _decrementIndex,
            tooltip: 'Prev',
            child: const Icon(Icons.remove),
          ),
          SizedBox(height: 10),
          FloatingActionButton(
            onPressed: _incrementindex,
            tooltip: 'Next',
            child: const Icon(Icons.add),
          ),
        ],
      ), // This trailing comma makes auto-formatting nicer for build methods.
    );
  }
}

class InputWidget extends StatefulWidget {
  const InputWidget({
    super.key,
    required this.title,
